import React, { useState, useEffect, useRef } from "react";
import axios from "axios";
import Cookies from "js-cookie";
import { useNavigate } from "react-router-dom";
import { Modal } from "bootstrap";
import { toast } from "react-toastify";
import Toast from "../components/Toast";

const API_BASE_URL =
  process.env.REACT_APP_API_BASE_URL || "http://localhost:5000/api";

function UserManagement() {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(false);
  const [totalUsers, setTotalUsers] = useState(0);
  const [page, setPage] = useState(1);
  const [limit] = useState(10); // default page size
  const [searchTerm, setSearchTerm] = useState("");

  const [formData, setFormData] = useState({
    id: null,
    prefix: "Mr",
    fullName: "",
    phone: "",
    email: "",
    status: "",
    source: "",
    isConverted: false,
  });

  const modalRef = useRef(null);
  const navigate = useNavigate();

  /* ================= FETCH USERS ================= */
  function fetchUsers() {
    setLoading(true);
    const token = Cookies.get("adminToken");

    axios
      .get(API_BASE_URL + "/users", {
        headers: { Authorization: "Bearer " + token },
        params: {
          limit,
          offset: (page - 1) * limit,
          q: searchTerm || undefined,
        },
      })
      .then(function (response) {
        if (response.data.success) {
          setUsers(response.data.data);
          setTotalUsers(response.data.count || 0);
        } else {
          toast.error(response.data.error || "Failed to fetch users");
        }
      })
      .catch(function (err) {
        toast.error(err.response?.data?.error || "Error fetching users");
      })
      .finally(function () {
        setLoading(false);
      });
  }

  useEffect(
    function () {
      const token = Cookies.get("adminToken");
      if (!token) {
        navigate("/");
      } else {
        fetchUsers();
      }
    },
    [navigate, page, searchTerm]
  );

  /* ================= INPUT CHANGE ================= */
  function handleInputChange(e) {
    const { name, value } = e.target;

    setFormData((prev) => {
      const updated = { ...prev };
      if (name === "isConverted") {
        updated[name] = value === "true";
      } else {
        updated[name] = value;
      }
      return updated;
    });
  }

  /* ================= SEARCH CHANGE ================= */
  function handleSearchChange(e) {
    setSearchTerm(e.target.value);
    setPage(1); // reset to first page when searching
  }

  /* ================= EDIT ================= */
  function handleEdit(user) {
    setFormData({
      id: user.id,
      prefix: user.prefix,
      fullName: user.fullName,
      phone: user.phone,
      email: user.email,
      status: user.status,
      source: user.source,
      isConverted: user.isConverted,
    });

    const modalElement = document.getElementById("editUserModal");
    modalRef.current = new Modal(modalElement);
    modalRef.current.show();
  }

  /* ================= UPDATE ================= */
  function handleSubmit(e) {
    e.preventDefault();

    const token = Cookies.get("adminToken");

    axios
      .put(API_BASE_URL + "/users/" + formData.id, formData, {
        headers: { Authorization: "Bearer " + token },
      })
      .then(function () {
        toast.success("User updated successfully");
        fetchUsers();
        modalRef.current.hide();
      })
      .catch(function (err) {
        toast.error(err.response?.data?.error || "Update failed");
      });
  }

  /* ================= DELETE ================= */
  function handleDelete(id) {
    if (!window.confirm("Are you sure you want to delete this user?")) {
      return;
    }

    const token = Cookies.get("adminToken");

    axios
      .delete(API_BASE_URL + "/users/" + id, {
        headers: { Authorization: "Bearer " + token },
      })
      .then(function () {
        toast.success("User deleted successfully");
        fetchUsers();
      })
      .catch(function (err) {
        toast.error(err.response?.data?.error || "Delete failed");
      });
  }

  /* ================= PAGINATION ================= */
  const totalPages = Math.ceil(totalUsers / limit);

  function goToPage(p) {
    if (p >= 1 && p <= totalPages) {
      setPage(p);
    }
  }

  /* ================= UI ================= */
  return (
    <div className="container mt-3">
      <Toast />
      <div className="row mb-3">
        <div className="col">
          <i
            className="fa fa-arrow-left mt-2"
            style={{ cursor: "pointer" }}
            onClick={() => navigate("/dashboard")}
          ></i>
        </div>
      </div>

      <div className="row mb-3">
        <div className="col">
          <h4 className="fw-bold mb-0">User Management</h4>
        </div>
      </div>

      {/* ================= SEARCH INPUT ================= */}
      <div className="row mb-3">
        <div className="col-md-4 col-12">
          <input
            type="text"
            className="form-control"
            placeholder="Search by name, email, or phone"
            value={searchTerm}
            onChange={handleSearchChange}
          />
        </div>
      </div>

      <div className="card mb-3">
        <div className="card border-0">
          {loading ? (
            <div className="text-center">Loading...</div>
          ) : (
            <div className="table-responsive rounded">
              <table className="table table-bordered table-hover mb-0">
                <thead className="table-dark">
                  <tr>
                    <th>ID</th>
                    <th>Prefix</th>
                    <th>Name</th>
                    <th>Phone</th>
                    <th>Email</th>
                    <th>Status</th>
                    <th>Source</th>
                    <th>Converted</th>
                    <th>Created At</th>
                    <th>Updated At</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {users.map((user) => (
                    <tr key={user.id}>
                      <td>{user.id}</td>
                      <td>{user.prefix}</td>
                      <td>{user.fullName}</td>
                      <td>{user.phone}</td>
                      <td>{user.email}</td>
                      <td>{user.status}</td>
                      <td>{user.source}</td>
                      <td>{user.isConverted ? "Yes" : "No"}</td>
                      <td>{new Date(user.createdAt).toLocaleString()}</td>
                      <td>{new Date(user.updatedAt).toLocaleString()}</td>
                      <td>
                        <i
                          className="fa-solid fa-pen-to-square text-primary me-3"
                          style={{ cursor: "pointer" }}
                          onClick={() => handleEdit(user)}
                          title="Edit User"
                        ></i>
                        <i
                          className="fa-solid fa-trash text-danger"
                          style={{ cursor: "pointer" }}
                          onClick={() => handleDelete(user.id)}
                          title="Delete User"
                        ></i>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>

      {/* ================= PAGINATION CONTROLS ================= */}
      {totalPages > 1 && (
        <nav>
          <ul className="pagination">
            <li className={`page-item ${page === 1 ? "disabled" : ""}`}>
              <button className="page-link" onClick={() => goToPage(page - 1)}>
                Previous
              </button>
            </li>
            {Array.from({ length: totalPages }, (_, i) => (
              <li
                key={i + 1}
                className={`page-item ${page === i + 1 ? "active" : ""}`}
              >
                <button className="page-link" onClick={() => goToPage(i + 1)}>
                  {i + 1}
                </button>
              </li>
            ))}
            <li className={`page-item ${page === totalPages ? "disabled" : ""}`}>
              <button className="page-link" onClick={() => goToPage(page + 1)}>
                Next
              </button>
            </li>
          </ul>
        </nav>
      )}

      {/* ================= EDIT MODAL ================= */}
      <div className="modal fade" id="editUserModal" tabIndex="-1">
        <div className="modal-dialog modal-dialog-centered">
          <div className="modal-content">
            <form onSubmit={handleSubmit}>
              <div className="modal-header">
                <h5 className="modal-title">Edit User</h5>
                <button
                  type="button"
                  className="btn-close"
                  data-bs-dismiss="modal"
                ></button>
              </div>

              <div className="modal-body">
                <div className="mb-3">
                  <label>Prefix</label>
                  <select
                    name="prefix"
                    className="form-select"
                    value={formData.prefix}
                    onChange={handleInputChange}
                  >
                    <option value="Mr">Mr</option>
                    <option value="Mrs">Mrs</option>
                    <option value="Miss">Miss</option>
                  </select>
                </div>

                <div className="mb-3">
                  <label>Full Name</label>
                  <input
                    type="text"
                    name="fullName"
                    className="form-control"
                    value={formData.fullName}
                    onChange={handleInputChange}
                    required
                  />
                </div>

                <div className="mb-3">
                  <label>Phone</label>
                  <input
                    type="text"
                    name="phone"
                    className="form-control"
                    value={formData.phone}
                    onChange={handleInputChange}
                    required
                  />
                </div>

                <div className="mb-3">
                  <label>Email</label>
                  <input
                    type="email"
                    name="email"
                    className="form-control"
                    value={formData.email}
                    onChange={handleInputChange}
                    required
                  />
                </div>

                <div className="mb-3">
                  <label>Status</label>
                  <select
                    name="status"
                    className="form-select"
                    value={formData.status}
                    onChange={handleInputChange}
                  >
                    <option value="Client">Client</option>
                    <option value="Lead">Lead</option>
                  </select>
                </div>

                <div className="mb-3">
                  <label>Source</label>
                  <input
                    type="text"
                    name="source"
                    className="form-control"
                    value={formData.source}
                    onChange={handleInputChange}
                  />
                </div>

                <div className="mb-3">
                  <label>Converted</label>
                  <select
                    name="isConverted"
                    className="form-select"
                    value={formData.isConverted ? "true" : "false"}
                    onChange={handleInputChange}
                  >
                    <option value="false">No</option>
                    <option value="true">Yes</option>
                  </select>
                </div>
              </div>

              <div className="modal-footer">
                <button type="submit" className="btn btn-primary">
                  Update
                </button>
              </div>
            </form>
          </div>
        </div>
      </div>
    </div>
  );
}

export default UserManagement;
